import type { IGomokuPiece } from '@algorithm.ts/gomoku'
import { GomokuDirections } from '@algorithm.ts/gomoku'
import shuffle from '@algorithm.ts/knuth-shuffle'
import { GomokuPlayerType } from '@kyokuya/react-game-gomoku-core'
import type { IPlayer } from '../../types'
import { BasePlayer } from './BasePlayer'

export class StupidComputerPlayer extends BasePlayer implements IPlayer {
  public readonly type: GomokuPlayerType = GomokuPlayerType.COMPUTER_STUPID
  public readonly automatic: boolean = true

  public override init(): void {}

  public override move(_pieces: ReadonlyArray<IGomokuPiece>): [r: number, c: number] {
    if (_pieces.length <= 0) {
      const mr: number = this.MAX_ROW >> 1
      const mc: number = this.MAX_COL >> 1
      return [mr, mc]
    }

    const pieces = _pieces.slice()
    shuffle(pieces)

    const directions = GomokuDirections.slice()
    shuffle(directions)

    for (const piece of pieces) {
      for (const [dr, dc] of directions) {
        const nr: number = piece.r + dr
        const nc: number = piece.c + dc
        if (nr >= 0 && nr < this.MAX_ROW && nc >= 0 && nc < this.MAX_COL) {
          if (pieces.find(piece => piece.r === nr && piece.c === nc)) continue
          return [nr, nc]
        }
      }
    }
    return [-1, -1]
  }

  public override forward(): void {}
}
