import { css } from '@emotion/css'
import React from 'react'
import shallow from 'zustand/shallow'
import Seo from '@/component/seo'
import { useDependencyContext } from '@/core/context'

export interface IGamePageProps {
  seoTitle: string
  title?: React.ReactNode
  children: React.ReactNode
}

export const GamePage: React.FC<IGamePageProps> = props => {
  const { useSiteStore } = useDependencyContext()
  const [author, copyright] = useSiteStore(({ state }) => [state.author, state.copyright], shallow)
  const classes = useStyles()

  return (
    <div className={classes.container}>
      <Seo title={props.seoTitle} />
      <header className={classes.header}>
        <h1>{props.title ?? props.seoTitle}</h1>
      </header>
      <main className={classes.main}>{props.children}</main>
      <footer className={classes.footer}>
        <div className={classes.footerWrapper}>
          <span>
            © {copyright.date} {author.name}
          </span>
          <span>{author.motto}</span>
        </div>
      </footer>
    </div>
  )
}

