import invariant from '@guanghechen/invariant'
import { useReactiveRef } from '@guanghechen/react-hooks'
import { GameRunningStatus } from '@kyokuya/react-game-core'
import { GomokuActionType } from '@kyokuya/react-game-gomoku-core'
import React from 'react'
import { GomokuGameContextType } from '../context/context'
import type { IPlayer } from '../types'

export interface ICurrentPlayer {
  move(clickedPos?: { r: number; c: number }): void
}

export const useCurrentPlayer = (): ICurrentPlayer => {
  const { state, dispatch } = React.useContext(GomokuGameContextType)
  const stateRef = useReactiveRef(state)

  const players = state.players
  const currentPlayerRef = useReactiveRef<IPlayer | null>(players[state.currentPlayerId])
  const gameLockRef = React.useRef<boolean>(false)

  const move = React.useCallback(
    (clickedPos?: { r: number; c: number }): void => {
      const currentPlayer = currentPlayerRef.current
      if (gameLockRef.current || !currentPlayer) return

      const { GOMOKU_SIZE, gameStatus } = stateRef.current
      if (gameStatus !== GameRunningStatus.RUNNING) return

      gameLockRef.current = true
      try {
        const MAX_ROW: number = GOMOKU_SIZE
        const MAX_COL: number = GOMOKU_SIZE
        const [r, c] = currentPlayer.move(stateRef.current.pieces, clickedPos)

        invariant(
          r >= 0 && r < MAX_ROW && c >= 0 && c <= MAX_COL,
          () =>
            `[Unexpected moving] currentPlayer: ${JSON.stringify(
              currentPlayer,
            )}, moving: (${r}, ${c})`,
        )

        dispatch({ type: GomokuActionType.MOVE, payload: { r, c } })
      } finally {
        gameLockRef.current = false
      }
    },
    [dispatch, players, stateRef, currentPlayerRef],
  )

  React.useEffect(() => {
    const player = currentPlayerRef.current
    if (player?.automatic) {
      // Don't stub the canvas drawer.
      setTimeout(move, 0)
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [state.attemptTick, state.gameStatus])

  return { move }
}
