import type { IGomokuPiece } from '@algorithm.ts/gomoku'
import { GomokuPlayerType } from '@kyokuya/react-game-gomoku-core'
import type { IPlayer } from '../../types'
import { BasePlayer } from './BasePlayer'

export class HumanPlayer extends BasePlayer implements IPlayer {
  public readonly type: GomokuPlayerType = GomokuPlayerType.HUMAN
  public readonly automatic: boolean = false

  public override init(): void {}

  public override move(
    _pieces: ReadonlyArray<IGomokuPiece>,
    clickedPos?: { r: number; c: number },
  ): [r: number, c: number] {
    if (clickedPos) {
      const { r, c } = clickedPos
      return [r, c]
    }
    return [-1, -1]
  }

  public override forward(): void {}
}
