import type { IGomokuAction, IGomokuState } from '@kyokuya/react-game-gomoku-core'
import {
  GomokuActionType,
  builtinReducer as baseBuiltinReducer,
} from '@kyokuya/react-game-gomoku-core'
import { createPlayer } from '../core/player/createPlayer'
import type { IPlayer } from '../types'
import type { IGomokuGameAction } from './action'
import { GomokuGameActionType } from './action'
import type { IGomokuGameContextMiddleware } from './context'
import type { IGomokuGameState } from './state'

const baseReducer = baseBuiltinReducer(state => state)
export const builtinReducer: IGomokuGameContextMiddleware =
  next =>
  (_state: IGomokuGameState, action: IGomokuGameAction): IGomokuGameState => {
    const { players, ...baseState } = _state
    const nextBaseState: IGomokuState = baseReducer(baseState, action as IGomokuAction)
    const state: IGomokuGameState =
      nextBaseState === baseState ? _state : { ...nextBaseState, players: _state.players }

    switch (action.type) {
      case GomokuGameActionType.RESET_PLAYERS: {
        const { playerId, playerName, playerType } = action.payload
        const nextPlayers = state.players.map(player => {
          if (player.id !== playerId) return player
          if (playerType && player.type !== playerType) {
            return createPlayer({
              playerId,
              playerType,
              playerName: playerName ?? player.name,
              MAX_ROW: state.GOMOKU_SIZE,
              MAX_COL: state.GOMOKU_SIZE,
            })
          }

          player.reset({ name: playerName })
          return player
        })
        return { ...state, players: nextPlayers }
      }
      case GomokuGameActionType.FLIP: {
        const [player0, player1] = state.players
        player1.reset({ playerId: 0 })
        player0.reset({ playerId: 1 })
        return { ...state, players: [player1, player0] }
      }
    }

    switch (action.type) {
      case GomokuActionType.RESET: {
        if (state.GOMOKU_SIZE === _state.GOMOKU_SIZE) return state

        const players: IPlayer[] = state.players.map(player =>
          createPlayer({
            playerId: player.id,
            playerType: player.type,
            playerName: player.name,
            MAX_ROW: state.GOMOKU_SIZE,
            MAX_COL: state.GOMOKU_SIZE,
          }),
        )
        return { ...state, players }
      }
      case GomokuActionType.MOVE: {
        const { r, c } = action.payload
        for (const player of state.players) player.forward(r, c, _state.currentPlayerId)
        return state
      }
      case GomokuActionType.RETRACT: {
        for (const player of players) player.init(state.pieces)
        return state
      }
      default: {
        return next(state, action)
      }
    }
  }
