import { GomokuPlayerType } from '@kyokuya/react-game-gomoku-core'
import type { IPlayer } from '../../types'
import { defaultPreferenceSettings } from './BasePlayer'
import { CleverComputerPlayer } from './CleverComputerPlayer'
import { HumanPlayer } from './HumanPlayer'
import { StupidComputerPlayer } from './StupidComputerPlayer'

export const createPlayer = (params: {
  playerId: number
  playerType: GomokuPlayerType
  playerName: string
  MAX_ROW: number
  MAX_COL: number
}): IPlayer => {
  const { playerId, playerType, playerName, MAX_ROW, MAX_COL } = params
  const preferenceSettings = { ...defaultPreferenceSettings[playerId] }
  switch (playerType) {
    case GomokuPlayerType.HUMAN:
      return new HumanPlayer({ name: playerName, playerId, MAX_ROW, MAX_COL, preferenceSettings })
    case GomokuPlayerType.COMPUTER:
      return new CleverComputerPlayer({
        name: playerName,
        playerId,
        MAX_ROW,
        MAX_COL,
        MAX_ADJACENT: 5,
        MAX_DISTANCE_OF_NEIGHBOR: 2,
        preferenceSettings,
      })
    case GomokuPlayerType.COMPUTER_STUPID:
      return new StupidComputerPlayer({
        name: playerName,
        playerId,
        MAX_ROW,
        MAX_COL,
        preferenceSettings,
      })
  }
}
