import { css } from '@emotion/css'
import { useReactiveRef } from '@guanghechen/react-hooks'
import { GameRunningStatus } from '@kyokuya/react-game-core'
import type { GomokuPlayerType } from '@kyokuya/react-game-gomoku-core'
import { GomokuActionType } from '@kyokuya/react-game-gomoku-core'
import React from 'react'
import { GomokuGameActionType } from '../context/action'
import { GomokuGameContextType } from '../context/context'
import { GameSettingsGomokuSize } from './GameSettingsGomokuSize'
import { GameSettingsPlayer } from './GameSettingsPlayer'

export const GameSettings: React.FC = () => {
  const { state, dispatch } = React.useContext(GomokuGameContextType)
  const stateRef = useReactiveRef(state)

  const actions = React.useMemo(
    () => ({
      onSizeChange: (size: number): void => {
        dispatch({ type: GomokuActionType.RESET, payload: { GOMOKU_SIZE: size } })
      },
      onPlayerChange: (
        playerId: number,
        playerType?: GomokuPlayerType,
        playerName?: string,
      ): void => {
        dispatch({
          type: GomokuGameActionType.RESET_PLAYERS,
          payload: { playerId, playerType, playerName },
        })
      },
    }),
    [dispatch, stateRef],
  )

  const classes = useStyles()
  const isPending: boolean = state.gameStatus === GameRunningStatus.PENDING

  return (
    <div className={classes.container}>
      <GameSettingsGomokuSize
        className={classes.item}
        size={state.GOMOKU_SIZE}
        disabled={!isPending}
        onSizeChange={actions.onSizeChange}
      />
      {state.players.map((player, playerId) => (
        <GameSettingsPlayer
          key={playerId}
          className={classes.item}
          itemTitle={`Player${playerId + 1}`}
          playerId={playerId}
          playerType={player.type}
          playerName={player.name}
          disabled={!isPending}
          onChanged={actions.onPlayerChange}
        />
      ))}
    </div>
  )
}

// eslint-disable-next-line @typescript-eslint/explicit-function-return-type
const useStyles = () => {
  return React.useMemo(
    () => ({
      container: css`
        display: flex;
        flex-direction: column;
        justify-content: space-between;
        margin: auto;
      `,
      item: css`
        line-height: 3rem;
      `,
    }),
    [],
  )
}
